import { Component, EventEmitter, Input, Output } from '@angular/core';

export interface TemplateFilterState {
  role: string;
  experience: string;
  layout: string;
  style: string;
  category: string;
  isAts: boolean;
  premiumOnly: boolean;
}

@Component({
  selector: 'app-template-filter-sidebar',
  templateUrl: './template-filter-sidebar.component.html'
})
export class TemplateFilterSidebarComponent {
  @Input() filters!: TemplateFilterState;
  @Output() filtersChange = new EventEmitter<TemplateFilterState>();

  readonly roles = ['developer', 'designer', 'mba'];
  readonly experienceLevels = ['fresher', 'mid', 'senior'];
  readonly layouts = ['single-column', 'two-column'];
  readonly styles = ['modern', 'minimal', 'creative', 'clean', 'compact'];
  readonly categories = ['Fresher', 'Developer', 'Professional', 'Modern', 'Compact'];

  update(partial: Partial<TemplateFilterState>): void {
    this.filtersChange.emit({ ...this.filters, ...partial });
  }
}
<aside class="shell-card h-fit p-5">
  <div>
    <p class="eyebrow">Categories</p>
    <div class="mt-4 flex flex-wrap gap-2">
      <button *ngFor="let category of categories" class="rounded-full px-3 py-2 text-xs font-semibold transition"
              [ngClass]="filters.category === category ? 'bg-[#5b5cf0] text-white' : 'bg-[#f8f9ff] text-[#475467]'"
              (click)="update({ category: filters.category === category ? '' : category })">
        {{ category }}
      </button>
    </div>
  </div>

  <div class="mt-6 space-y-5">
    <div>
      <p class="text-sm font-bold text-[#17172b]">Role</p>
      <div class="mt-3 flex flex-wrap gap-2">
        <button *ngFor="let role of roles" class="rounded-full px-3 py-2 text-xs font-semibold transition"
                [ngClass]="filters.role === role ? 'bg-[#5b5cf0] text-white' : 'bg-[#f8f9ff] text-[#475467]'"
                (click)="update({ role: filters.role === role ? '' : role })">
          {{ role | titlecase }}
        </button>
      </div>
    </div>

    <div>
      <p class="text-sm font-bold text-[#17172b]">Experience</p>
      <div class="mt-3 flex flex-wrap gap-2">
        <button *ngFor="let level of experienceLevels" class="rounded-full px-3 py-2 text-xs font-semibold transition"
                [ngClass]="filters.experience === level ? 'bg-[#5b5cf0] text-white' : 'bg-[#f8f9ff] text-[#475467]'"
                (click)="update({ experience: filters.experience === level ? '' : level })">
          {{ level | titlecase }}
        </button>
      </div>
    </div>

    <div>
      <p class="text-sm font-bold text-[#17172b]">Layout</p>
      <div class="mt-3 flex flex-wrap gap-2">
        <button *ngFor="let layout of layouts" class="rounded-full px-3 py-2 text-xs font-semibold transition"
                [ngClass]="filters.layout === layout ? 'bg-[#5b5cf0] text-white' : 'bg-[#f8f9ff] text-[#475467]'"
                (click)="update({ layout: filters.layout === layout ? '' : layout })">
          {{ layout === 'single-column' ? 'Single Column' : 'Two Column' }}
        </button>
      </div>
    </div>

    <div>
      <p class="text-sm font-bold text-[#17172b]">Style</p>
      <div class="mt-3 flex flex-wrap gap-2">
        <button *ngFor="let style of styles" class="rounded-full px-3 py-2 text-xs font-semibold transition"
                [ngClass]="filters.style === style ? 'bg-[#5b5cf0] text-white' : 'bg-[#f8f9ff] text-[#475467]'"
                (click)="update({ style: filters.style === style ? '' : style })">
          {{ style | titlecase }}
        </button>
      </div>
    </div>

    <label class="flex items-center justify-between rounded-2xl bg-[#f8f9ff] px-4 py-3 text-sm font-semibold text-[#17172b]">
      ATS Friendly
      <input type="checkbox" class="h-4 w-4 accent-[#5b5cf0]" [ngModel]="filters.isAts" (ngModelChange)="update({ isAts: $event })">
    </label>

    <label class="flex items-center justify-between rounded-2xl bg-[#f8f9ff] px-4 py-3 text-sm font-semibold text-[#17172b]">
      Free / Premium
      <input type="checkbox" class="h-4 w-4 accent-[#5b5cf0]" [ngModel]="filters.premiumOnly" (ngModelChange)="update({ premiumOnly: $event })">
    </label>
  </div>
</aside>
